import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { FiArrowRight, FiStar, FiClock, FiTrendingUp } from 'react-icons/fi';
import api from '../../services/api';
import ProductCard from '../../components/ProductCard';

const Home = () => {
  const [categories, setCategories] = useState([]);
  const [popularItems, setPopularItems] = useState([]);
  const [trendingItems, setTrendingItems] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [catRes, popRes, trendRes] = await Promise.all([
          api.get('/categories'),
          api.get('/recommendations/popular'),
          api.get('/recommendations/trending')
        ]);
        setCategories(catRes.data.categories);
        setPopularItems(popRes.data.popular);
        setTrendingItems(trendRes.data.trending);
      } catch (err) {
        console.error('Error fetching data:', err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  if (loading) {
    return (
      <div className="flex items-center justify-center h-96">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-primary-500"></div>
      </div>
    );
  }

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      <section className="bg-gradient-to-r from-primary-500 to-primary-600 rounded-2xl p-8 md:p-12 mb-10 text-white">
        <h1 className="text-3xl md:text-4xl font-bold mb-4">Welcome to Smart Cafe</h1>
        <p className="text-primary-100 text-lg mb-6 max-w-xl">
          Order your favorite food, track it in real-time, and enjoy a seamless dining experience.
        </p>
        <Link to="/menu" className="inline-flex items-center gap-2 bg-white text-primary-500 font-semibold px-6 py-3 rounded-lg hover:bg-primary-50 transition-colors">
          Explore Menu <FiArrowRight />
        </Link>
      </section>

      <section className="mb-10">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-2xl font-bold text-dark-800">Categories</h2>
          <Link to="/menu" className="text-primary-500 hover:underline flex items-center gap-1">
            View All <FiArrowRight size={16} />
          </Link>
        </div>
        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-6 gap-4">
          {categories.map((cat) => (
            <Link
              key={cat._id}
              to={`/menu?category=${cat._id}`}
              className="card p-4 text-center hover:border-primary-500 border-2 transition-all"
            >
              <div className="w-12 h-12 bg-primary-50 rounded-full flex items-center justify-center mx-auto mb-3">
                <span className="text-2xl">{
                  cat.name === 'Beverages' ? '☕' :
                  cat.name === 'Snacks' ? '🍪' :
                  cat.name === 'Main Course' ? '🍛' :
                  cat.name === 'Desserts' ? '🍰' :
                  cat.name === 'Breakfast' ? '🥞' : '🥗'
                }</span>
              </div>
              <h3 className="font-medium text-dark-800 text-sm">{cat.name}</h3>
            </Link>
          ))}
        </div>
      </section>

      {popularItems.length > 0 && (
        <section className="mb-10">
          <div className="flex items-center gap-2 mb-6">
            <FiStar className="text-yellow-500 fill-current" size={24} />
            <h2 className="text-2xl font-bold text-dark-800">Popular Items</h2>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
            {popularItems.slice(0, 8).map((product) => (
              <ProductCard key={product._id} product={product} />
            ))}
          </div>
        </section>
      )}

      {trendingItems.length > 0 && (
        <section className="mb-10">
          <div className="flex items-center gap-2 mb-6">
            <FiTrendingUp className="text-secondary-500" size={24} />
            <h2 className="text-2xl font-bold text-dark-800">Trending This Week</h2>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
            {trendingItems.slice(0, 4).map((item) => (
              <ProductCard key={item._id} product={{ ...item, _id: item._id }} />
            ))}
          </div>
        </section>
      )}

      <section className="bg-dark-800 rounded-2xl p-8 text-white text-center">
        <h2 className="text-2xl font-bold mb-3">QR Code Ordering</h2>
        <p className="text-dark-300 mb-4">Scan the QR code at your table to order directly!</p>
        <div className="inline-flex items-center gap-2 text-primary-400">
          <FiClock />
          <span>Fast • Easy • Contactless</span>
        </div>
      </section>
    </div>
  );
};

export default Home;
